const items = $input.all();
return items.map(item => {
  const j = item.json || {};
  const contactId = (j.contact_id === undefined || j.contact_id === null || j.contact_id === '') ? null : String(j.contact_id);
  const phone = (j.phone === undefined || j.phone === null) ? null : String(j.phone);
  const source = (j.source === undefined || j.source === null) ? null : String(j.source);
  const externalId = (j.external_id === undefined || j.external_id === null) ? null : String(j.external_id);
  const objective = (j.objective === undefined || j.objective === null) ? null : String(j.objective);
  const city = (j.city === undefined || j.city === null) ? null : String(j.city);
  const callbackPeriod = (j.callback_period === undefined || j.callback_period === null) ? null : String(j.callback_period);
  let kommoData = j.kommo_data;
  if (kommoData === undefined || kommoData === null) kommoData = {};
  if (typeof kommoData === 'string') {
    try { kommoData = JSON.parse(kommoData); } catch (e) { kommoData = {}; }
  }
  if (typeof kommoData !== 'object' || Array.isArray(kommoData)) kommoData = {};
  const testRunId = (j.test_run_id === undefined || j.test_run_id === null) ? null : String(j.test_run_id);
  return {
    json: {
      contact_id: contactId,
      phone,
      source,
      external_id: externalId,
      objective,
      city,
      callback_period: callbackPeriod,
      kommo_data: kommoData,
      kommo_data_json: JSON.stringify(kommoData),
      test_run_id: testRunId
    }
  };
});

const validated = $('Validate Payload').first().json;
const items = $input.all();
return items.map(item => {
  const j = item.json || {};
  const leadId = j.lead_id || null;
  const contactId = j.contact_id || null;
  return {
    json: {
      lead_id: leadId,
      contact_id: contactId,
      source: validated.source,
      external_id: validated.external_id,
      test_run_id: validated.test_run_id,
      event_payload_json: JSON.stringify({
        lead_id: leadId,
        contact_id: contactId,
        source: validated.source,
        external_id: validated.external_id,
        test_run_id: validated.test_run_id
      })
    }
  };
});
